"use client";

import { useEffect, useMemo, useState } from "react";
import Link from "next/link";
import { auth, db } from "../lib/firebase";
import { onAuthStateChanged, signOut } from "firebase/auth";
import { collection, getDocs, query, where } from "firebase/firestore";

export default function Home() {
  const [products, setProducts] = useState([]);
  const [selectedCategory, setSelectedCategory] = useState("tatca");
  const [user, setUser] = useState(null);
  const [isAdmin, setIsAdmin] = useState(false);
  const [showUserMenu, setShowUserMenu] = useState(false);

  useEffect(() => {
    const fetchProducts = async () => {
      try {
        const querySnapshot = await getDocs(collection(db, "products"));
        const data = querySnapshot.docs.map((doc) => ({
          id: doc.id,
          ...doc.data(),
        }));
        setProducts(data);
      } catch (error) {
        console.error("Lỗi lấy sản phẩm:", error);
      }
    };

    fetchProducts();
  }, []);

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (u) => {
      setUser(u);

      if (!u) {
        setIsAdmin(false);
        return;
      }

      const q = query(collection(db, "users"), where("uid", "==", u.uid));
      const querySnapshot = await getDocs(q);

      if (!querySnapshot.empty) {
        const userData = querySnapshot.docs[0].data();
        setIsAdmin(userData.role === "admin");
      } else {
        setIsAdmin(false);
      }
    });

    return () => unsub();
  }, []);

  const filteredProducts = useMemo(() => {
    if (selectedCategory === "tatca") return products;
    return products.filter((item) => item.category === selectedCategory);
  }, [products, selectedCategory]);

  const featuredProducts = filteredProducts
    .filter((item) => item.featured)
    .slice(0, 6);

  const vnd = (price) => Number(price).toLocaleString("vi-VN") + "đ";

  const categories = [
    {
      id: "tatca",
      name: "Tất cả",
      desc: "Toàn bộ sản phẩm nổi bật",
      image:
        "https://i.pinimg.com/736x/7c/e1/46/7ce1467799f125762966b84879191148.jpg",
      href: "/san-pham?category=tatca",
    },
    {
      id: "den",
      name: "Đèn decor",
      desc: "Ánh sáng ấm cho không gian sống",
      image:
        "data:image/webp;base64,",
      href: "/san-pham?category=den",
    },
    {
      id: "trangtri",
      name: "Đồ trang trí",
      desc: "Tinh giản, hiện đại, dễ phối",
      image:
        "data:image/webp;base64,",
      href: "/san-pham?category=trangtri",
    },
    {
      id: "ao",
      name: "Hot trend",
      desc: "Sản phẩm trẻ trung, dễ chọn",
      image:
        "https://i.pinimg.com/1200x/c2/3f/cf/c23fcf90068d2da94f911a5b11b85661.jpg",
      href: "/san-pham?category=ao",
    },
  ];

  return (
    <main className="min-h-screen bg-[#f7f3ee] text-[#171717]">
      <header className="sticky top-0 z-50 border-b border-black/5 bg-[#f7f3ee]/90 backdrop-blur">
        <div className="mx-auto flex max-w-7xl items-center justify-between px-6 py-4">
          <Link href="/" className="text-xl font-semibold tracking-wide">
            Hisu Store
          </Link>

          <nav className="hidden items-center gap-8 text-sm md:flex">
            <a href="#bo-suu-tap" className="hover:opacity-70">
              Bộ sưu tập
            </a>
            <Link href="/san-pham" className="hover:opacity-70">
              Sản phẩm
            </Link>
            <Link href="/gio-hang" className="hover:opacity-70">
              Giỏ hàng
            </Link>
          </nav>

          <div className="flex items-center gap-3">
            {user ? (
              <>
                <div className="relative">
                  <button
                    onClick={() => setShowUserMenu(!showUserMenu)}
                    className="rounded-full border border-black/10 bg-white px-4 py-2 text-sm shadow-sm"
                  >
                    {isAdmin
                      ? `Admin: ${user.displayName || user.email}`
                      : `${user.displayName || user.email}`}
                  </button>

                  {showUserMenu && (
                    <div className="absolute right-0 mt-2 w-52 overflow-hidden rounded-2xl border border-black/10 bg-white shadow-xl">
                      {!isAdmin && (
                        <Link
                          href="/don-hang"
                          onClick={() => setShowUserMenu(false)}
                          className="block px-4 py-3 text-sm hover:bg-[#f4efe8]"
                        >
                          Đơn hàng của tôi
                        </Link>
                      )}

                      <Link
                        href="/doi-mat-khau"
                        onClick={() => setShowUserMenu(false)}
                        className="block px-4 py-3 text-sm hover:bg-[#f4efe8]"
                      >
                        Đổi mật khẩu
                      </Link>

                      <button
                        onClick={() => signOut(auth)}
                        className="block w-full px-4 py-3 text-left text-sm hover:bg-[#f4efe8]"
                      >
                        Đăng xuất
                      </button>
                    </div>
                  )}
                </div>

                {isAdmin && (
                  <Link
                    href="/admin"
                    className="hidden rounded-full bg-black px-4 py-2 text-sm text-white md:inline-block"
                  >
                    Quản lý
                  </Link>
                )}
              </>
            ) : (
              <>
                <Link
                  href="/dang-nhap"
                  className="rounded-full border border-black/10 bg-white px-4 py-2 text-sm"
                >
                  Đăng nhập
                </Link>
                <Link
                  href="/dang-ky"
                  className="rounded-full bg-black px-4 py-2 text-sm text-white"
                >
                  Đăng ký
                </Link>
              </>
            )}
          </div>
        </div>
      </header>

      <section className="mx-auto max-w-7xl px-6 pt-8 pb-10">
         <div className="grid items-center gap-6 lg:grid-cols-[1.05fr_1fr]">
          {/* Cột trái */}
          <div className="flex h-full flex-col justify-center rounded-[32px] bg-[#e8dfd2] px-8 py-8 lg:px-10 lg:py-10">
            <p className="mb-5 text-[13px] uppercase tracking-[0.35em] text-neutral-500">
              Bộ sưu tập nổi bật
            </p>

            <h1 className="max-w-[520px] text-5xl font-semibold leading-[1.08] tracking-tight text-neutral-900 lg:text-6xl">
              Không gian đẹp cho căn phòng của bạn
            </h1>

            <p className="mt-6 max-w-[560px] text-[17px] leading-8 text-neutral-600">
              Đèn decor, đồ trang trí và sản phẩm hot trend theo phong cách hiện đại,
              tối giản, dễ phối với nhiều không gian sống.
            </p>

            <div className="mt-8 flex flex-wrap gap-3">
              <a
                href="#san-pham"
                className="rounded-full bg-black px-6 py-3 text-sm font-medium text-white"
              >
                Xem sản phẩm
              </a>

              <a
                href="#bo-suu-tap"
                className="rounded-full border border-neutral-200 bg-white px-6 py-3 text-sm font-medium text-neutral-800"
              >
                Khám phá bộ sưu tập
              </a>
            </div>
          </div>

          {/* Cột phải */}
          <div className="aspect-[1.25] overflow-hidden rounded-[32px]">
            <img
              src="https://i.pinimg.com/1200x/8d/3e/25/8d3e252fd87cef9dc66a62410265adf7.jpg"
              alt="Không gian nội thất"
              className="h-full w-full object-cover"
            />
          </div>
        </div>
      </section>

      <section
        id="bo-suu-tap"
        className="mx-auto max-w-7xl px-6 py-8"
      >
        <div className="mb-8 text-center">
          <p className="text-sm uppercase tracking-[0.2em] text-black/50">
            Danh mục
          </p>
          <h2 className="mt-2 text-2xl font-semibold">
            Bộ sưu tập theo nhu cầu
          </h2>
        </div>

        <div className="grid gap-5 md:grid-cols-2 xl:grid-cols-4">
          {categories.map((cat) => (
            <Link
              key={cat.id}
              href={cat.href}
              className="group rounded-[20px] border border-black/20 p-[2px] bg-white text-left transition hover:-translate-y-1 hover:shadow-md"
            >
              <div className="relative h-60 overflow-hidden rounded-[18px]">
                <img
                  src={cat.image}
                  alt={cat.name}
                  className="h-full w-full object-cover transition duration-500 group-hover:scale-105"
                />
                <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-black/15 to-transparent" />
                <div className="absolute bottom-0 p-4 text-white">
                  <p className="text-xs uppercase tracking-[0.2em] text-white/75">
                    Hisu Store
                  </p>
                  <h3 className="mt-2 text-xl font-semibold">{cat.name}</h3>
                  <p className="mt-2 text-sm text-white/80">{cat.desc}</p>
                </div>
              </div>
            </Link>
          ))}
        </div>
      </section>

      <section id="san-pham" className="mx-auto max-w-7xl px-4 py-6">
        <div className="mb-8 text-center">
          <p className="text-sm uppercase tracking-[0.2em] text-black/50">
            Sản phẩm
          </p>
          <h2 className="mt-2 text-2xl font-semibold">
            Sản phẩm nổi bật
          </h2>
        </div>

        {featuredProducts.length === 0 ? (
          <div className="rounded-[20px] bg-white p-10 text-center text-black/60">
            Chưa có sản phẩm trong danh mục này.
          </div>
        ) : (
          <>
            <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">
              {featuredProducts.map((item) => (
                <Link
                  key={item.id}
                  href={`/san-pham/${item.id}`}
                  className="group block overflow-hidden rounded-[18px] bg-white shadow-sm transition hover:shadow-md"
                >
                  <div className="relative aspect-[8/5] overflow-hidden">
                    <img
                      src={item.image}
                      alt={item.name}
                      className="h-full w-full object-cover transition duration-500 group-hover:scale-105"
                    />
                  </div>

                  <div className="p-3">
                    <p className="text-[11px] uppercase tracking-[0.16em] text-black/45">
                      {item.category === "den"
                        ? "Đèn decor"
                        : item.category === "trangtri"
                        ? "Đồ trang trí"
                        : "Hot trend"}
                    </p>

                    <h3 className="mt-2 text-lg font-semibold leading-snug">
                      {item.name}
                    </h3>

                    <p className="mt-2 line-clamp-2 text-sm leading-6 text-black/55">
                      {item.description}
                    </p>

                    <div className="mt-4 flex items-center justify-between">
                      <p className="text-lg font-semibold">{vnd(item.price)}</p>

                      <button
                        onClick={(e) => {
                          e.preventDefault();

                          const cartKey = auth.currentUser
                            ? `cart_${auth.currentUser.uid}`
                            : "cart_guest";

                          let cart = JSON.parse(localStorage.getItem(cartKey) || "[]");

                          const exist = cart.find((p) => p.id === item.id);

                          if (exist) {
                            exist.quantity += 1;
                          } else {
                            cart.push({
                              id: item.id,
                              name: item.name,
                              price: item.price,
                              image: item.image,
                              quantity: 1,
                            });
                          }

                          localStorage.setItem(cartKey, JSON.stringify(cart));
                          alert("Đã thêm vào giỏ hàng");
                        }}
                        className="rounded-full bg-black px-4 py-2 text-sm font-medium text-white"
                      >
                        Thêm vào giỏ hàng
                      </button>
                    </div>
                  </div>
                </Link>
              ))}
            </div>

            <div className="mt-8 flex justify-center">
              <Link
                href="/san-pham"
                className="rounded-full bg-black px-6 py-3 text-sm font-medium text-white transition hover:opacity-90"
              >
                Xem thêm
              </Link>
            </div>
          </>
        )}
      </section>

      <section className="mx-auto max-w-7xl px-6 py-8">
        <div className="grid gap-4 rounded-[32px] bg-white p-8 md:grid-cols-3">
          <div>
            <p className="text-sm uppercase tracking-[0.2em] text-black/45">
              Cam kết
            </p>
            <h3 className="mt-3 text-xl font-semibold">Phong cách tối giản, dễ sống cùng</h3>
          </div>

          <div className="text-sm leading-7 text-black/60">
            Sản phẩm phù hợp nhiều kiểu không gian, dễ phối màu và dễ dùng cho
            phòng ngủ, phòng khách, góc làm việc.
          </div>
        </div>
      </section>

      <footer id="lien-he" className="mt-8 border-t border-black/5">
        <div className="mx-auto flex max-w-7xl flex-col gap-4 px-4 py-6 md:flex-row md:items-center md:justify-between">
          <div>
            <h3 className="text-xl font-semibold">Hisu Store</h3>
            <p className="mt-2 text-sm text-black/55">
              Web bán nội thất, đèn decor và sản phẩm hot trend.
            </p>
          </div>

          <div className="text-sm leading-7 text-black/55">
            © 2026 Hisu Store
            <br />
            Phong cách - Phong cách - Phong cách - mck
          </div>
        </div>
      </footer>
    </main>
  );
}